import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { toast, ToastContainer } from 'react-toastify';
import 'react-toastify/dist/ReactToastify.css';

const Register = () => {
  const [formData, setFormData] = useState({
    Username: '',
    Password: '',
    ClientCode: ''
  });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const validatePassword = (password) => {
    const errors = [];
    if (!/[A-Z]/.test(password)) {
      errors.push("Password must have at least one uppercase letter ('A'-'Z')");
    }
    if (!/[0-9]/.test(password)) {
      errors.push("Password must have at least one digit ('0'-'9')");
    }
    if (!/[^A-Za-z0-9]/.test(password)) {
      errors.push("Password must have at least one non-alphanumeric character");
    }
    return errors;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    const passwordErrors = validatePassword(formData.Password);
    if (passwordErrors.length > 0) {
      setError(passwordErrors.join('\n'));
      setLoading(false);
      return;
    }

    try {
      await axios.post('https://soni.loyalstring.co.in/api/ProductMaster/AuthRegister', formData);
      toast.success('Registration successful! Please login.', {
        position: "top-right",
        autoClose: 3000,
        theme: "colored"
      });
      navigate('/login');
    } catch (err) {
      const errorMessage = err.response?.data || 'Registration failed. Please try again.';
      setError(Array.isArray(errorMessage) ? errorMessage.map(e => e.Description).join('\n') : errorMessage);
      toast.error('Registration failed. Please check the requirements.', {
        position: "top-right",
        autoClose: 3000,
        theme: "colored"
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{
      minHeight: '100vh',
      background: 'linear-gradient(135deg, #f8ffae 0%, #43c6ac 100%)',
      fontFamily: 'Poppins, Montserrat, Arial, sans-serif',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center'
    }}>
      <ToastContainer />
      <div className="row justify-content-center w-100">
        <div className="col-md-6">
          <div className="card shadow-lg border-0" style={{ borderRadius: 18 }}>
            <div className="card-body p-5">
              <div className="text-center mb-4">
                <i className="fas fa-id-card fa-3x text-success mb-2"></i>
                <h2 className="card-title mb-1 fw-bold" style={{ fontFamily: 'Poppins, Montserrat, Arial, sans-serif', letterSpacing: 1 }}>RFID API Register</h2>
                <div className="mb-2 text-primary fw-semibold" style={{ fontSize: '1.1rem', letterSpacing: 1 }}>Loyalstring Pvt Ltd</div>
                <div className="text-muted mb-2" style={{ fontSize: '0.95rem' }}>Create your account to access the RFID API Dashboard</div>
              </div>
              {error && <div className="alert alert-danger poppins" style={{ whiteSpace: 'pre-line', fontWeight: 500 }}><i className="fas fa-exclamation-triangle me-2"></i>{error}</div>}
              <form onSubmit={handleSubmit} autoComplete="off">
                <div className="mb-3">
                  <label htmlFor="Username" className="form-label fw-semibold">
                    <i className="fas fa-user me-2 text-primary"></i>Username
                  </label>
                  <input
                    type="text"
                    className="form-control shadow-sm"
                    id="Username"
                    name="Username"
                    value={formData.Username}
                    onChange={handleChange}
                    required
                    placeholder="Enter your email or username"
                  />
                </div>
                <div className="mb-3">
                  <label htmlFor="ClientCode" className="form-label fw-semibold">
                    <i className="fas fa-building me-2 text-warning"></i>Client Code
                  </label>
                  <input
                    type="text"
                    className="form-control shadow-sm"
                    id="ClientCode"
                    name="ClientCode"
                    value={formData.ClientCode}
                    onChange={handleChange}
                    required
                    placeholder="Enter your client code"
                  />
                </div>
                <div className="mb-3">
                  <label htmlFor="Password" className="form-label fw-semibold">
                    <i className="fas fa-lock me-2 text-danger"></i>Password
                  </label>
                  <input
                    type="password"
                    className="form-control shadow-sm"
                    id="Password"
                    name="Password"
                    value={formData.Password}
                    onChange={handleChange}
                    required
                    placeholder="Create a strong password"
                  />
                  <small className="text-muted">
                    Password must contain:
                    <ul className="mb-0">
                      <li>At least one uppercase letter</li>
                      <li>At least one number</li>
                      <li>At least one special character</li>
                    </ul>
                  </small>
                </div>
                <button
                  type="submit"
                  className="btn btn-success w-100 fw-bold shadow-sm poppins"
                  style={{ fontSize: '1.1rem', letterSpacing: 1, transition: '0.2s', boxShadow: '0 2px 8px rgba(67,198,172,0.15)' }}
                  disabled={loading}
                  onMouseOver={e => e.currentTarget.style.background = '#43c6ac'}
                  onMouseOut={e => e.currentTarget.style.background = ''}
                >
                  {loading ? (
                    <>
                      <span className="spinner-border spinner-border-sm me-2" role="status" aria-hidden="true"></span>
                      Registering...
                    </>
                  ) : (
                    <>
                      <i className="fas fa-user-plus me-2"></i>
                      Register
                    </>
                  )}
                </button>
              </form>
              <div className="text-center mt-3">
                <p className="mb-0">
                  Already have an account?{' '}
                  <a href="/login" className="fw-bold text-primary text-decoration-none" style={{ transition: 'color 0.2s' }}>
                    <i className="fas fa-sign-in-alt me-1"></i>Login
                  </a>
                </p>
              </div>
            </div>
          </div>
        </div>
      </div>
      {/* Google Fonts for Poppins */}
      <link href="https://fonts.googleapis.com/css2?family=Poppins:wght@400;600&family=Montserrat:wght@500&display=swap" rel="stylesheet" />
    </div>
  );
};

export default Register;
